sql_answer:
SELECT COUNT(*) AS events_above_avg_spending
FROM (SELECT b.link_to_event, SUM(b.spent) AS total_spent FROM budget b GROUP BY b.link_to_event) x
WHERE x.total_spent > (SELECT AVG(total_spent) FROM (SELECT b.link_to_event, SUM(b.spent) AS total_spent FROM budget b GROUP BY b.link_to_event) y);

SELECT COUNT(DISTINCT a.link_to_member) AS members_in_popular_events
FROM attendance a
WHERE a.link_to_event IN (SELECT link_to_event FROM attendance GROUP BY link_to_event HAVING COUNT(*) > (SELECT AVG(cnt) FROM (SELECT COUNT(*) AS cnt FROM attendance GROUP BY link_to_event) x));

SELECT COUNT(*) AS products_above_avg FROM (
SELECT p.ProductID, SUM(t.Amount * t.Price) AS total_revenue FROM transactions_1k t JOIN products p ON t.ProductID = p.ProductID GROUP BY p.ProductID
HAVING SUM(t.Amount * t.Price) > (SELECT AVG(r) FROM (SELECT SUM(Amount * Price) AS r FROM transactions_1k GROUP BY ProductID) x)) q;

SELECT COUNT(DISTINCT t.GasStationID) AS gasstations_with_high_txn
FROM transactions_1k t JOIN gasstations g ON t.GasStationID = g.GasStationID
WHERE (t.Amount * t.Price) > (SELECT AVG(t2.Amount * t2.Price) FROM transactions_1k t2 WHERE t2.GasStationID = t.GasStationID);

SELECT COUNT(DISTINCT t.CustomerID) AS customers_never_bought_product_1
FROM transactions_1k t
WHERE NOT EXISTS (SELECT 1 FROM transactions_1k t2 WHERE t2.CustomerID = t.CustomerID AND t2.ProductID = 1);

SELECT COUNT(DISTINCT s.id)
FROM superhero s
JOIN hero_power hp ON s.id = hp.hero_id;

SELECT p.publisher_name, AVG(pc.power_count) AS avg_powers_per_hero
FROM publisher p JOIN superhero s ON s.publisher_id = p.id JOIN (SELECT hero_id, COUNT(*) AS power_count FROM hero_power GROUP BY hero_id) pc ON pc.hero_id = s.id
GROUP BY p.publisher_name HAVING AVG(pc.power_count) > (SELECT AVG(cnt) FROM (SELECT COUNT(*) AS cnt FROM hero_power GROUP BY hero_id) x) ORDER BY avg_powers_per_hero DESC;

SELECT COUNT(*) 
FROM superhero s
WHERE NOT EXISTS (
  SELECT 1 FROM hero_power hp WHERE hp.hero_id = s.id
);

SELECT COUNT(*) AS heroes_most_common_eye_colour
FROM superhero s
WHERE s.eye_colour_id = (
  SELECT eye_colour_id FROM superhero GROUP BY eye_colour_id ORDER BY COUNT(*) DESC LIMIT 1
);

SELECT COUNT(*) AS cards_after_1995
FROM card
WHERE issued > '1995-01-01';

SELECT COUNT(*) AS gold_cards
FROM card
WHERE type = 'gold';

SELECT x.client_id, x.total_amount
FROM (SELECT d.client_id, SUM(t.amount) AS total_amount FROM disp d JOIN trans t ON d.account_id=t.account_id GROUP BY d.client_id) x
WHERE x.total_amount > (SELECT AVG(total_per_client) FROM (SELECT SUM(t.amount) AS total_per_client FROM disp d JOIN trans t ON d.account_id=t.account_id GROUP BY d.client_id) y);

SELECT COUNT(*)
FROM satscores
WHERE NumGE1500 >= 50;

SELECT sname
FROM satscores
WHERE (AvgScrRead+AvgScrMath+AvgScrWrite) > 1200;

SELECT sc.County, MAX(ss.AvgScrRead) AS max_read
FROM schools sc JOIN satscores ss ON sc.CDSCode = ss.cds
GROUP BY sc.County HAVING max_read > 550;

SELECT sc.County
FROM schools sc JOIN satscores ss ON sc.CDSCode=ss.cds
GROUP BY sc.County HAVING AVG(ss.AvgScrRead)>(SELECT AVG(AvgScrRead) FROM satscores);

SELECT sc.County
FROM schools sc JOIN satscores ss ON sc.CDSCode=ss.cds WHERE ss.AvgScrMath>ss.AvgScrRead
GROUP BY sc.County HAVING COUNT(*)>=5;

SELECT sc.County, AVG(ss.AvgScrRead+ss.AvgScrMath+ss.AvgScrWrite) AS avg_total
FROM schools sc JOIN satscores ss ON sc.CDSCode=ss.cds GROUP BY sc.County
ORDER BY avg_total DESC LIMIT 5;

SELECT sc.County FROM schools sc JOIN satscores ss ON sc.CDSCode=ss.cds
WHERE (ss.AvgScrRead+ss.AvgScrMath+ss.AvgScrWrite)>(SELECT AVG(AvgScrRead+AvgScrMath+AvgScrWrite) FROM satscores)
GROUP BY sc.County HAVING COUNT(*)>5;
